-----------------------------------------------------------------
local BaseIcon = LXImport(".BaseIcon")
-----------------------------------------------------------------
---@class HeadIcon:BaseIcon
local HeadIcon = LxClass("HeadIcon", BaseIcon)
local typeUIText = typeof(CS.YXUIText)

function HeadIcon:HeadIcon(wndClass)
    self._wndClass = wndClass
    self._frameType = 0
end

function HeadIcon:OnCreate()
    self._isEnus = gLGameLanguage:IsEnglishVersion()

    self:SetTrans()
    self:RefreshUI()
end

function HeadIcon:SetHeadData(headData)
    self._heroData = {
        level = headData.level,
        headFrame = headData.headFrame,
        headFrameStr = headData.headFrameStr,
        icon = headData.headStr or self:GetHeadIcon(headData.icon),
        noLv = headData.noLv,
        bDefaultLayer = headData.bDefaultLayer,
        bDefaultSorting = headData.bDefaultSorting,
        bDefaultSortNum = headData.bDefaultSortNum,
        noEff = headData.noEff,
    }
    self:SetDefaultIcon("public_default_hero1")
    self:Create(headData.trans, headData.playerId, headData.func)
end

function HeadIcon:GetHeadIcon(refId)
    --获取头像,头像框，称号资源
    local str = ""
    local ref = GameTable.SnakeRolePlayerHeadRef[refId]
    if (ref) then
        str = ref.icon
    end
    return str
end

function HeadIcon:SetTrans()
    local uiTrans = self._uiTrans
    self._uiHeadFrameTrans = CS.FindTrans(uiTrans, "HeadFrame")
    self._lvText = CS.FindTrans(uiTrans, "LvXUIText")
    self._uiFrameEff = CS.FindTrans(uiTrans, "FrameEff")


end

function HeadIcon:SetData()
    local isShowLv = not self._heroData.noLv and self._heroData.level
    CS.ShowObject(self._lvText, isShowLv)
    if (isShowLv) then
        --local lv = LUtil.FormatHurtNumSpriteText(tonumber(self._heroData.level))
        local text = CS.FindTrans(self._uiTrans, "lvBg/level")
        self:SetXUIText(text, self._heroData.level)
        if nil == self._isEnus then
            self._isEnus = gLGameLanguage:IsEnglishVersion()
        end

        if self._isEnus then
            local uiText = text:GetComponent(typeUIText)
            local alignmentEnum = LxUiHelper.GetTMPAlignment(5)
            if alignmentEnum then
                uiText.alignment = alignmentEnum
            end
            LxUiHelper.SetAnchoredPosition(text,0,-3.4)
        end

    end

    local bg = CS.FindTrans(self._uiTrans, "lvBg")
    CS.ShowObject(bg, isShowLv)
end

function HeadIcon:RefreshUI()
    local icon = self._heroData.icon
    local headFrame = self._heroData.headFrame
    local headFrameStr = self._heroData.headFrameStr
    if LxUiHelper.IsImgPathValid(icon) then
        self:SetCommonImg(self._uiIconTrans, icon)
    end
    if headFrameStr then
        self:SetCommonImg(self._uiHeadFrameTrans, headFrameStr)
        CS.ShowObject(self._uiHeadFrameTrans, true)
    end
    self._frameType = 0
    if headFrame then
        local ref = gModelPlayer:GetRolePlayerHeadRefByRefId(headFrame)
        if not ref then
            return
        end
        local headFrameIcon = ref.icon
        if LxUiHelper.IsImgPathValid(headFrameIcon) then
            self:SetCommonImg(self._uiHeadFrameTrans, headFrameIcon)
            CS.ShowObject(self._uiHeadFrameTrans, true)
            self._frameType = 1
        end
        if ref.effect and ref.effect ~= "" and not self._heroData.noEff then
            local bDefaultLayer = self._heroData.bDefaultLayer or false
            local bDefaultSorting = self._heroData.bDefaultSorting or false
            local bDefaultSortNum = self._heroData.bDefaultSortNum or 0
            local InstanceID = self._uiFrameEff:GetInstanceID()
            self._wndClass:DestroyWndEffectByKey(InstanceID)
            self._wndClass:DestroyWndSpineByKey(InstanceID)

            local effectname = ref.effect
            local hideBadge = ref.hideBadge or 0
            if self:IsSpineEffect(effectname) then
                local func = function(spine)
                    spine:SetRaycastTarget(false)
                end
                self._wndClass:CreateWndSpine(self._uiFrameEff, effectname, InstanceID, bDefaultLayer, func, nil, true)
                CS.ShowObject(self._uiFrameEff, true)
                CS.ShowObject(self._uiHeadFrameTrans, hideBadge ~= 1)
                self._frameType = 3
            else
                self._wndClass:CreateWndEffect(self._uiFrameEff, effectname, InstanceID, 100, bDefaultLayer, bDefaultSorting, bDefaultSortNum)
                CS.ShowObject(self._uiFrameEff, true)
                CS.ShowObject(self._uiHeadFrameTrans, hideBadge ~= 1)
                self._frameType = 2
            end

        else
            CS.ShowObject(self._uiFrameEff, false)
            CS.ShowObject(self._uiHeadFrameTrans, true)
            self._frameType = 1
        end
    end
end

function HeadIcon:IsSpineEffect(effectname)
    local fullPath = LxResPathUtil.GetEffectPath(effectname)
    if not fullPath then
        printInfoNR("AutoEffectRef[effectname] is not find, effectname = " .. (effectname or "nil"))
        return false
    end
    if string.find(string.lower(fullPath), "spine/") then
        return true
    end
    return false
end

function HeadIcon:OnAniHeadFrame(bAni)
    if self._frameType == 2 then
        if bAni then
            CS.ShowObject(self._uiFrameEff, false)
            CS.ShowObject(self._uiHeadFrameTrans, true)
        else
            CS.ShowObject(self._uiFrameEff, true)
            CS.ShowObject(self._uiHeadFrameTrans, false)
        end
    end
end

return HeadIcon
